import{_ as t,o as r,c as o,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"RFC 0008 — Security & encryption architecture","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0008-security-encryption-architecture.md","filePath":"rfcs/0008-security-encryption-architecture.md"}'),n={name:"rfcs/0008-security-encryption-architecture.md"};function a(i,e,d,c,l,p){return r(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="rfc-0008-—-security-encryption-architecture" tabindex="-1">RFC 0008 — Security &amp; encryption architecture <a class="header-anchor" href="#rfc-0008-—-security-encryption-architecture" aria-label="Permalink to &quot;RFC 0008 — Security &amp; encryption architecture&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Whole platform — runtime, <code>apps/auth</code>, <code>packages/db</code>, <code>packages/sdk</code>, <code>packages/manifest</code>, <code>bin/sv</code>, Docker/Compose, <code>.env.example</code>, docs, SRS; amends RFC 0006 &amp; 0007<br><strong>Incorporated into plan:</strong> Yes, <strong>phased</strong> — SRS §3.17, §5 (<code>crypto:use</code>). <strong>Tier 0 (hardening) + Tier 1 (transport) ship in v1</strong> (Task 0.5.16); <strong>at-rest encryption, field-level <code>sdk.crypto</code> + <code>crypto:use</code>, and zero-knowledge E2EE (Tiers 2–4) are post-v1</strong> (Task 1.0.1). The reserved <code>sdk.crypto</code> stub + <code>crypto:use</code> permission land with the post-v1 task.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Establish Sovereign&#39;s <strong>security &amp; encryption architecture</strong> as a layered, threat-model-driven roadmap — not a single feature. We <strong>harden</strong> (security headers, transport), <strong>encrypt at rest</strong> (databases, avatars, backups, exports) under a <strong>local-keyfile envelope key hierarchy</strong>, <strong>specify</strong> field-level encryption behind a reserved <code>sdk.crypto</code>, and <strong>chart</strong> zero-knowledge end-to-end encryption honestly as the post-v1 direction.</p><p>The guiding stance: deliver real, verifiable privacy wins now (a stolen disk or leaked backup yields ciphertext) <strong>without overpromising</strong> an E2EE model the current server-side-rendering + server-side-plugin architecture cannot yet support. Encryption is <strong>opt-in and operator-owned</strong>: the operator holds the key, and <strong>losing it means losing the data</strong> — that is the cost of true ownership.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign&#39;s positioning is &quot;open source, privacy-first, owned entirely by the person or organisation running it.&quot; The cryptographic baseline does not yet match that promise:</p><ul><li><strong>Nothing is encrypted at rest</strong> — <code>sovereign.db</code>, <code>auth.db</code>, and avatars are plaintext on disk; Postgres has no SSL configured.</li><li><strong>No security headers</strong> — CSP, HSTS, <code>X-Frame-Options</code>, <code>X-Content-Type-Options</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code> are unset.</li><li><strong>Backups and exports are plaintext</strong> — RFC 0006 archives and RFC 0007 export bundles carry personal data in the clear (0007 flags bundle encryption as an open question).</li><li><strong>The internal channel is plaintext HTTP</strong> — runtime↔auth over the Docker network.</li></ul><p>What is already solid: Argon2id password hashing (better-auth), HMAC-signed session cookies, httpOnly cookies (AUTH-04), secrets with no defaults (NFR-08), and <strong>no telemetry</strong> (confirmed — there is no outbound data collection). This RFC builds the rest on that foundation.</p><p>The SRS lists <strong>E2EE as out-of-scope for v1</strong> (§4.6), and &quot;simplicity over premature flexibility&quot; is a guiding principle. This RFC respects both: it commits to the achievable tiers and treats zero-knowledge as a charted, post-v1 direction rather than a v1 deliverable.</p><h2 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat model&quot;">​</a></h2><p>Encryption choices are only meaningful against a stated adversary. <strong>Assets:</strong> the identity DB (<code>auth.db</code>), the platform DB (<code>sovereign.db</code>), plugin data, avatars/blobs, backups, export bundles, secrets/keys, and live sessions.</p><table tabindex="0"><thead><tr><th>Threat</th><th>Tier that addresses it</th><th>Residual risk</th></tr></thead><tbody><tr><td>Network sniffing / MITM</td><td><strong>Transport</strong> (TLS/HSTS, Postgres SSL, internal channel)</td><td>Endpoint compromise.</td></tr><tr><td>Stolen disk / leaked backup / VPS snapshot</td><td><strong>At-rest</strong> (volume / DB / backup / blob encryption)</td><td>Key stored on the same host (see below).</td></tr><tr><td>Curious/malicious host or hosting provider</td><td><strong>Field-level</strong> (key off-box) → <strong>zero-knowledge</strong></td><td>At-rest alone does <strong>not</strong> stop someone who can read RAM/key.</td></tr><tr><td>Compromised or curious plugin</td><td>SDK boundary (exists) + field scoping</td><td>A plugin still sees its own users&#39; data.</td></tr><tr><td>RCE / compromised server process</td><td><strong>Only zero-knowledge E2EE</strong> mitigates</td><td>With server-held keys, an attacker with code execution wins.</td></tr><tr><td>Co-tenant user on a shared instance</td><td>Access control (exists) + per-user keys</td><td>Admin can still act on the instance.</td></tr></tbody></table><p><strong>Honest framing of server-held keys (Tiers 0–3):</strong> at-rest encryption protects data <em>off</em> the running host (theft, backups, decommissioned disks). It does <strong>not</strong> protect against an attacker who already controls the live process or the key — that requires Tier 4. We state this plainly rather than implying &quot;encrypted&quot; means &quot;private from the operator.&quot;</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Secrets with no defaults</strong> — <code>apps/auth/src/env.ts</code> throws on missing <code>AUTH_SECRET</code> / <code>SOVEREIGN_ADMIN_KEY</code>; the envelope KEK follows the same rule.</li><li><strong>HMAC session cookies</strong> — signed cache verified offline in <code>runtime/src/session-verify.ts</code> (<code>resolveAuthSecret</code>); Argon2id via better-auth; httpOnly cookies (AUTH-04).</li><li><strong>Reserved-surface pattern</strong> — <code>packages/sdk/src/unimplemented.ts</code> / <code>packages/sdk/src/data.ts</code> stubs throw <code>NotImplementedError</code>; the manifest enum reserves matching permissions (<code>packages/manifest/src/schema.ts</code>). Reused for <code>sdk.crypto</code> + <code>crypto:use</code>.</li><li><strong>Plaintext baseline</strong> — <code>packages/db/src/client.ts</code>, <code>apps/auth/src/db.ts</code>, avatars in <code>runtime/app/api/account/avatar/route.ts</code>; no headers in the Next configs or <code>runtime/middleware.ts</code>; no Postgres SSL.</li><li><strong><code>SECURITY.md</code></strong> exists (disclosure policy + scope); there is <strong>no threat-model document</strong> yet — this RFC adds <code>docs/security.md</code>.</li><li><strong>Amends RFC 0006</strong> (<code>sv backup</code> archives) and <strong>RFC 0007</strong> (export ZIP, open question #4) to encrypted.</li></ul><h2 id="proposed-architecture-—-tiers" tabindex="-1">Proposed architecture — tiers <a class="header-anchor" href="#proposed-architecture-—-tiers" aria-label="Permalink to &quot;Proposed architecture — tiers&quot;">​</a></h2><p>All tiers below are <strong>deferred</strong> (specified for post-acceptance tasks) except the reserved <code>sdk.crypto</code> stub noted under &quot;Adoption path&quot;.</p><h3 id="tier-0-—-hardening-cheapest-ship-first" tabindex="-1">Tier 0 — Hardening (cheapest, ship first) <a class="header-anchor" href="#tier-0-—-hardening-cheapest-ship-first" aria-label="Permalink to &quot;Tier 0 — Hardening (cheapest, ship first)&quot;">​</a></h3><p>Security response headers on every response — <strong>CSP</strong>, <strong>HSTS</strong> (prod), <code>X-Frame-Options</code>, <code>X-Content-Type-Options: nosniff</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code> — via Next <code>headers()</code> in both apps&#39; <code>next.config.ts</code> plus <code>runtime/middleware.ts</code> for dynamic cases; cookie hardening review; log/PII redaction; codify the <strong>no-telemetry</strong> guarantee; and a new <strong><code>docs/security.md</code></strong> holding this threat model + a self-hoster hardening checklist.</p><h3 id="tier-1-—-transport" tabindex="-1">Tier 1 — Transport <a class="header-anchor" href="#tier-1-—-transport" aria-label="Permalink to &quot;Tier 1 — Transport&quot;">​</a></h3><p>Enforce TLS/HSTS at the edge (reverse proxy already terminates TLS — document and require it); add Postgres <code>sslmode=require</code> + certificate handling in <code>packages/db/src/client.ts</code>; optionally authenticate/encrypt the internal runtime↔auth channel (shared secret or mTLS). Mostly configuration + docs.</p><h3 id="tier-2-—-at-rest-encryption-server-held-key-—-the-main-deliverable" tabindex="-1">Tier 2 — At-rest encryption (server-held key — the main deliverable) <a class="header-anchor" href="#tier-2-—-at-rest-encryption-server-held-key-—-the-main-deliverable" aria-label="Permalink to &quot;Tier 2 — At-rest encryption (server-held key — the main deliverable)&quot;">​</a></h3><p><strong>Key hierarchy (envelope).</strong> A single <strong>master key-encryption key (KEK)</strong> is supplied locally — an env var or a host keyfile, <strong>no default, fail-fast when encryption is enabled</strong> (same discipline as <code>AUTH_SECRET</code>). The KEK wraps <strong>data-encryption keys (DEKs)</strong> (per store, and per user/tenant where Tier 3 needs them); wrapped DEKs live in the DB. Rotation re-wraps DEKs under a new KEK without bulk data re-encryption. <strong>The KEK is the operator&#39;s to keep and to back up separately</strong> — see Key management.</p><p>Four combinable mechanisms (all four are in scope per the design decision):</p><ul><li><strong>2a — Operator disk/volume encryption.</strong> LUKS / encrypted Docker volume, documented as the baseline. App unchanged; protects a powered-off disk.</li><li><strong>2b — App-level database encryption.</strong> SQLCipher via <code>better-sqlite3-multiple-ciphers</code> for <code>sovereign.db</code> + <code>auth.db</code>, opened with a key derived from the KEK. Postgres relies on TDE/disk + <code>sslmode</code> (no portable app-level per-cluster TDE) — documented. Protects DB files even on a shared filesystem, independent of disk encryption.</li><li><strong>2c — Encrypted backups &amp; exports.</strong> <code>sv backup</code> encrypts its archive (age / AES-GCM + passphrase); RFC 0007 export bundles gain optional passphrase/age encryption. <strong>Resolves the RFC 0006 / 0007 gaps directly.</strong></li><li><strong>2d — Avatar / blob encryption.</strong> On-disk user files are encrypted under a DEK and decrypted on serve in the avatar route (<code>runtime/app/api/account/avatar/...</code>).</li></ul><h3 id="tier-3-—-field-level-encryption-specified-deferred" tabindex="-1">Tier 3 — Field-level encryption (specified, deferred) <a class="header-anchor" href="#tier-3-—-field-level-encryption-specified-deferred" aria-label="Permalink to &quot;Tier 3 — Field-level encryption (specified, deferred)&quot;">​</a></h3><p>A reserved <strong><code>sdk.crypto</code></strong> surface lets a plugin encrypt designated sensitive values before they hit the DB and decrypt on read, using envelope encryption with a <strong>per-user DEK</strong> the runtime injects (a plugin never handles the raw KEK):</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// reserved — throws NotImplementedError in v1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.crypto.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">encryptField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(plaintext: string): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">string</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// returns opaque ciphertext token</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.crypto.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">decryptField</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ciphertext: string): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">string</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Gated by a new manifest permission <strong><code>crypto:use</code></strong>. Caveat: encrypting a column <strong>breaks DB-side search/sort</strong> on it; optional <strong>blind indexes</strong> (keyed hashes) can restore equality lookup. Field-level keeps the key off the disk that holds the ciphertext only if the KEK is sourced from outside that disk — otherwise it is defense-in-depth over Tier 2, not protection from the operator.</p><h3 id="tier-4-—-zero-knowledge-e2ee-charted-aspirational" tabindex="-1">Tier 4 — Zero-knowledge / E2EE (charted, aspirational) <a class="header-anchor" href="#tier-4-—-zero-knowledge-e2ee-charted-aspirational" aria-label="Permalink to &quot;Tier 4 — Zero-knowledge / E2EE (charted, aspirational)&quot;">​</a></h3><p>Keys derived from each user&#39;s passphrase (Argon2id) on the <strong>client</strong>; data encrypted client-side; the server stores <strong>ciphertext only</strong>. This is the only tier that defends against a curious operator or an RCE attacker — but it <strong>breaks</strong> a great deal of how Sovereign works today:</p><ul><li>server-side search and SSR of user content;</li><li>server-side plugin processing, aggregation, and notifications/email of content;</li><li>admin support workflows that read user data;</li><li>password reset becomes <strong>data loss</strong> without a separate recovery key;</li><li>multi-device requires client-side key sync.</li></ul><p>It is therefore a <strong>major architectural shift</strong>, realistically <strong>per-plugin opt-in</strong>, aligned with the post-v1 <strong>federated-systems (&quot;fs&quot;)</strong> direction, and <strong>out of v1 scope</strong> (SRS §4.6). This RFC charts it so later work has a target, not a v1 commitment.</p><h2 id="key-management-cross-cutting" tabindex="-1">Key management (cross-cutting) <a class="header-anchor" href="#key-management-cross-cutting" aria-label="Permalink to &quot;Key management (cross-cutting)&quot;">​</a></h2><ul><li><strong>Default: local keyfile / passphrase</strong>, no external dependency (NFR-02). The operator owns the KEK.</li><li><strong>Envelope hierarchy:</strong> KEK → wrapped DEK(s) in the DB; rotation re-wraps DEKs.</li><li><strong>Recovery is the operator&#39;s responsibility.</strong> <strong>Lose the KEK → lose the data</strong> (that is what &quot;owned entirely by you&quot; costs). The KEK must be backed up <strong>separately</strong> from encrypted backups — a backup encrypted under a key stored only inside that backup is worthless. Document this prominently; consider a printed recovery code.</li><li><strong>Optional pluggable KMS / Vault / OS-keyring adapter</strong> as a <em>future</em> backend for advanced operators — never the default, never required.</li><li><strong>Startup:</strong> fail-fast if encryption is enabled but the KEK is absent or wrong.</li></ul><h2 id="new-configuration-docker-impact" tabindex="-1">New configuration &amp; Docker impact <a class="header-anchor" href="#new-configuration-docker-impact" aria-label="Permalink to &quot;New configuration &amp; Docker impact&quot;">​</a></h2><p>New env vars (final names TBD): <code>SOVEREIGN_ENCRYPTION</code> (on/off), <code>SOVEREIGN_ENCRYPTION_KEY</code> or keyfile path, and a backup passphrase. On implementation this carries <strong>real Docker-config impact</strong> — the SQLCipher native dependency (<code>better-sqlite3-multiple-ciphers</code>) changes the image build and the <code>pnpm-workspace.yaml</code> <code>allowBuilds</code> allowlist, and <code>.env.example</code> + <code>docs/self-hosting.md</code> + the <code>runtime/src/docs-parity.test.ts</code> env-var parity check must be updated in the same change. (Flagged here; nothing changes in this doc-only draft.)</p><h2 id="impact-when-accepted-deferred-—-beyond-the-reserved-stub" tabindex="-1">Impact when accepted (deferred — beyond the reserved stub) <a class="header-anchor" href="#impact-when-accepted-deferred-—-beyond-the-reserved-stub" aria-label="Permalink to &quot;Impact when accepted (deferred — beyond the reserved stub)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where</th><th>Change</th></tr></thead><tbody><tr><td>runtime</td><td>Security headers (next config + middleware); avatar decrypt-on-serve.</td></tr><tr><td><code>apps/auth</code></td><td>DB encryption; security headers.</td></tr><tr><td><code>packages/db</code></td><td>SQLCipher driver option; Postgres SSL; envelope/key-management helpers.</td></tr><tr><td><code>packages/sdk</code></td><td>Implement <code>sdk.crypto</code> (replace the stub) against the runtime per-user DEK.</td></tr><tr><td><code>packages/manifest</code></td><td>Enforce <code>crypto:use</code>.</td></tr><tr><td><code>bin/sv</code></td><td>Encrypt backup archives.</td></tr><tr><td>RFC 0006 / RFC 0007</td><td>Amend to encrypted backups / encrypted export bundles.</td></tr><tr><td><code>.env.example</code>, <code>docs/self-hosting.md</code></td><td>New encryption env vars + setup/rotation/recovery procedures.</td></tr><tr><td><code>docs/security.md</code> (new)</td><td>Threat model + hardening checklist.</td></tr><tr><td>SRS §3 / §4</td><td>New <code>SEC-xx</code> requirement IDs + decision-log entry.</td></tr><tr><td><code>docs/roadmap.md</code></td><td>Sequenced tasks (Tier 0 → 1 → 2 → 3 → 4).</td></tr></tbody></table><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Cloud KMS as the default key store.</strong> Violates self-host / NFR-02 (no external dependency for core). Kept only as an <em>optional</em> future adapter.</li><li><strong>Full-disk encryption only.</strong> Necessary but insufficient — does nothing against a curious operator, a co-tenant, or a leaked logical backup. Adopted as the baseline (Tier 2a), not the whole story.</li><li><strong>End-to-end encryption now.</strong> Breaks server-side search/SSR/plugin processing and is out of v1 scope; charted as Tier 4 instead.</li><li><strong>Always-on per-field encryption.</strong> Significant performance and search/sort cost for data that is mostly not sensitive; field-level is opt-in (Tier 3).</li><li><strong>Rely entirely on the operator (no in-app crypto).</strong> Gives no verifiable in-product guarantee and clashes with the privacy-first positioning. Rejected in favour of the tiered model.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>SQLCipher native dependency.</strong> Does <code>better-sqlite3-multiple-ciphers</code> replace <code>better-sqlite3</code> outright, and what is the image-build / <code>allowBuilds</code> impact?</li><li><strong>Postgres at-rest story.</strong> Without portable app-level TDE, is disk encryption <ul><li><code>sslmode</code> the recommended posture, or pgcrypto for select columns?</li></ul></li><li><strong>better-auth under SQLCipher.</strong> Does the auth server&#39;s driver open an encrypted <code>auth.db</code> cleanly?</li><li><strong>Key rotation cost.</strong> Re-wrapping DEKs is cheap; any scenario forcing bulk re-encryption?</li><li><strong>Recovery model.</strong> Printed recovery code vs escrow vs &quot;you&#39;re on your own.&quot;</li><li><strong>Searchable encryption.</strong> Blind indexes for Tier 3 equality lookups — ship with Tier 3 or later?</li><li><strong>Encrypted DB × migrations.</strong> Interaction with the drizzle-kit / expand-contract flow (RFC 0006).</li><li><strong>Tier 2 key granularity.</strong> Single instance key vs per-user keys for at-rest.</li><li><strong>Performance overhead</strong> of SQLCipher + envelope ops on modest hardware (NFR-07: start &amp; serve within 10s on a 2-core/1GB VPS).</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>v1 — Tier 0 / 1 (Task 0.5.16):</strong> security headers + <code>docs/security.md</code> (threat model) + Postgres SSL + transport hardening. No new app secrets or native deps.</li><li><strong>post-v1 — reserved stub (Task 1.0.1):</strong> reserved <code>sdk.crypto</code> stub (<code>encryptField</code>/<code>decryptField</code> throw <code>NotImplementedError</code>) + <code>crypto:use</code> permission — additive (SDK + manifest <strong>minor</strong> bumps).</li><li><strong>post-v1 — Tier 2 (Task 1.0.1):</strong> key management (local KEK + envelope) → DB encryption (SQLCipher) → encrypted backups/exports (amend RFC 0006/0007) → avatar/blob encryption.</li><li><strong>post-v1 — Tier 3 (Task 1.0.1):</strong> implement <code>sdk.crypto</code> field-level encryption (+ optional blind indexes).</li><li><strong>post-v1 — Tier 4:</strong> zero-knowledge E2EE — per-plugin opt-in, aligned with the federation direction.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; threat model + tiered encryption roadmap; proposes reserved <code>sdk.crypto</code> + <code>crypto:use</code>.</td></tr><tr><td>1.0</td><td>Jun 2026</td><td>Accepted (phased); incorporated into SRS §3.17, §5 (<code>crypto:use</code>); Tier 0/1 → Task 0.5.16 (v1), Tiers 2–4 → Task 1.0.1 (post-v1).</td></tr><tr><td>1.1</td><td>Jun 2026</td><td><strong>Tier 0/1 implemented</strong> (Task 0.5.16): static security headers + HSTS (prod) and a strict nonce-based CSP on both apps; Postgres TLS via <code>sslmode</code>; new <code>docs/security.md</code>. Tiers 2–4 remain in Task 1.0.1.</td></tr></tbody></table>`,49)])])}const u=t(n,[["render",a]]);export{g as __pageData,u as default};
